INSERT INTO safety_incidents (incident_number, incident_date, incident_time, incident_type, severity, location, description, immediate_action, reported_by, injured_person, injury_type, body_part, witnesses, root_cause, status, closed_date) VALUES
('INC-2026-0001', '2026-01-08', '07:45', 'Near Miss', 'Minor', 'Loading Bay 2', 'Forklift nearly struck pedestrian worker who was crossing behind the vehicle without looking.', 'Area cordoned off. Driver and pedestrian both counselled on safety protocol.', 'J. Mokoena', '', '', '', 'S. Naidoo', 'Lack of designated pedestrian walkway markings in loading area.', 'Closed', '2026-01-15'),
('INC-2026-0002', '2026-01-14', '10:30', 'Injury', 'Moderate', 'Treatment Plant Floor', 'Operator sustained a cut to the right hand while handling broken sharps container.', 'First aid applied. Worker sent to clinic for stitches. Incident area cleaned.', 'M. Dlamini', 'T. Sibeko', 'Laceration', 'Right Hand', 'P. van Wyk, B. Khumalo', 'Damaged container not identified during receiving inspection.', 'Closed', '2026-01-28'),
('INC-2026-0003', '2026-01-22', '14:15', 'Unsafe Condition', 'Minor', 'Chemical Storage Room', 'Spill containment bund found cracked, allowing potential chemical seepage.', 'Area blocked off and maintenance called to assess repair.', 'R. Pillay', '', '', '', '', 'Ageing infrastructure. Bund not included in recent maintenance schedule.', 'Closed', '2026-02-05'),
('INC-2026-0004', '2026-02-03', '09:00', 'Property Damage', 'Minor', 'Parking Area', 'Delivery truck reversed into perimeter fence post causing minor damage.', 'Fence secured temporarily with cable ties. Repair scheduled.', 'A. Botha', '', '', '', 'D. Mthembu', 'Driver did not use spotter when reversing.', 'Closed', '2026-02-10'),
('INC-2026-0005', '2026-02-11', '11:20', 'Near Miss', 'Moderate', 'Autoclave Area', 'Steam release valve activated unexpectedly during maintenance. No injuries.', 'Maintenance halted. Equipment locked out and tagged out. Engineer consulted.', 'K. Govender', '', '', '', 'L. Nkosi, J. Mokoena', 'Lockout/tagout procedure not fully followed before maintenance began.', 'Closed', '2026-02-25'),
('INC-2026-0006', '2026-02-19', '06:30', 'Unsafe Act', 'Minor', 'Waste Receiving Bay', 'Worker observed sorting waste without wearing cut-resistant gloves.', 'Worker stopped immediately and issued correct PPE. Verbal warning issued.', 'S. Naidoo', '', '', '', '', 'Worker rushed to start shift, skipped PPE check.', 'Closed', '2026-02-20'),
('INC-2026-0007', '2026-03-05', '08:45', 'Injury', 'Minor', 'Admin Walkway', 'Employee slipped on wet floor near entrance. Bruised knee, no fracture.', 'First aid applied. Wet floor signs placed. Cleaning schedule reviewed.', 'P. van Wyk', 'N. Zulu', 'Bruise', 'Left Knee', 'A. Botha', 'No wet floor signage after early morning cleaning.', 'Closed', '2026-03-12'),
('INC-2026-0008', '2026-03-12', '13:00', 'Environmental', 'Moderate', 'Effluent Discharge Point', 'Elevated pH levels detected in effluent sample during routine testing.', 'Discharge halted. Sample sent to lab. Chemical dosing adjusted.', 'R. Pillay', '', '', '', '', 'Chemical dosing pump malfunction causing over-dosing of treatment chemicals.', 'Closed', '2026-03-20'),
('INC-2026-0009', '2026-03-18', '15:30', 'Near Miss', 'Minor', 'Loading Bay 1', 'Unsecured load shifted during transport within yard. No one in vicinity.', 'Load re-secured. Driver briefed on securing protocols.', 'D. Mthembu', '', '', '', 'T. Sibeko', 'Load straps were worn and not replaced during pre-trip inspection.', 'Closed', '2026-03-22'),
('INC-2026-0010', '2026-04-02', '10:00', 'Injury', 'Serious', 'Treatment Plant Floor', 'Operator experienced chemical splash to face when opening clogged treatment line.', 'Emergency eyewash used for 15 minutes. Transported to hospital immediately.', 'M. Dlamini', 'B. Khumalo', 'Chemical Burn', 'Face / Eyes', 'K. Govender, L. Nkosi', 'Blocked line built up pressure. SOP for clearing blockages not followed.', 'Corrective Action', null),
('INC-2026-0011', '2026-04-10', '07:15', 'Unsafe Condition', 'Minor', 'Emergency Exit B', 'Fire exit partially blocked by stored pallets.', 'Pallets removed immediately. Area cleared.', 'J. Mokoena', '', '', '', '', 'No assigned storage area for surplus pallets near treatment area.', 'Closed', '2026-04-11'),
('INC-2026-0012', '2026-04-17', '12:00', 'Near Miss', 'Minor', 'Truck Yard', 'Pedestrian gate left open allowing unauthorized vehicle access to pedestrian zone.', 'Gate closed and locked. Security informed.', 'A. Botha', '', '', '', 'S. Naidoo', 'Gate latch mechanism faulty. Security rounds missed this checkpoint.', 'Closed', '2026-04-20'),
('INC-2026-0013', '2026-04-25', '09:30', 'Unsafe Act', 'Moderate', 'Waste Sorting Area', 'Two workers not wearing face shields while handling pharmaceutical waste.', 'Workers stopped. PPE provided. Formal warning issued to both.', 'P. van Wyk', '', '', '', 'R. Pillay', 'Workers reported face shields were uncomfortable. Alternative shields to be sourced.', 'Corrective Action', null),
('INC-2026-0014', '2026-05-02', '14:45', 'Injury', 'Minor', 'Workshop', 'Maintenance worker pinched finger in equipment door. Minor swelling.', 'Ice applied. Worker returned to duties after rest.', 'K. Govender', 'D. Mthembu', 'Crush Injury', 'Right Index Finger', '', 'Equipment door spring tension too high.', 'Open', null),
('INC-2026-0015', '2026-05-08', '08:00', 'Environmental', 'Minor', 'Storm Water Drain', 'Oily sheen observed on storm water during heavy rain.', 'Oil absorbent booms deployed. Source traced to generator area.', 'R. Pillay', '', '', '', 'M. Dlamini', 'Generator drip tray overflow due to blocked drain hole.', 'Under Investigation', null),
('INC-2026-0016', '2026-05-15', '11:00', 'Near Miss', 'Moderate', 'Chemical Storage Room', 'Incompatible chemicals found stored on same shelf. Could have caused reaction.', 'Chemicals separated immediately. Storage audit initiated.', 'S. Naidoo', '', '', '', 'J. Mokoena, T. Sibeko', 'New stock placed by untrained temp worker.', 'Corrective Action', null),
('INC-2026-0017', '2026-05-22', '16:00', 'Property Damage', 'Minor', 'Treatment Plant Floor', 'Conveyor belt guard dislodged and fell, damaging sensor cable.', 'Equipment shut down. Maintenance called to repair guard and cable.', 'L. Nkosi', '', '', '', 'B. Khumalo', 'Guard mounting bolts had loosened over time. Not part of routine check.', 'Open', null),
('INC-2026-0018', '2026-05-28', '07:30', 'Unsafe Condition', 'Minor', 'Weighbridge Area', 'Weighbridge access ramp has uneven surface causing trip hazard.', 'Cones placed. Repair request submitted to facilities.', 'A. Botha', '', '', '', '', 'Surface erosion from heavy vehicle traffic.', 'Open', null);
