('INS-2026-0013', '2026-04-21', 'Equipment', 'Weighbridge', 'K. Govender', 'Calibration current. Ramp surface deteriorating (reported separately as incident).', 8, 7, 87.50, 'Requires Action', '2026-07-21'),
('INS-2026-0014', '2026-04-28', 'PPE Check', 'Treatment Plant', 'S. Naidoo', 'All PPE accounted for. Chemical aprons showing wear on 3 units. Ordered replacements.', 15, 12, 80.00, 'Requires Action', '2026-05-26'),
('INS-2026-0015', '2026-05-05', 'Site Walk', 'Full Site', 'J. Mokoena', 'Generator area cleaned. Storm drain repaired. Pedestrian gate latch replaced. Very good.', 25, 25, 100.00, 'Completed', '2026-06-02'),
