('INS-2026-0017', '2026-05-14', 'Vehicle', 'Truck Fleet', 'D. Mthembu', 'TF-003 brake lights repaired. All vehicles compliant. TF-007 windscreen chip noted.', 18, 17, 94.44, 'Completed', '2026-06-14'),
