INSERT INTO safety_risk_assessments (assessment_number, assessment_date, area, activity, hazard, risk_description, likelihood, consequence, risk_rating, risk_level, existing_controls, additional_controls, responsible_person, review_date, status, assessed_by) VALUES
('RA-2026-0001', '2026-01-10', 'Treatment Plant', 'Autoclave Operation', 'High pressure steam', 'Operator exposure to steam burns if safety valve fails or door seal leaks.', 2, 4, 8, 'High', 'Safety valves tested quarterly. Operators trained. PPE required.', 'Install pressure relief alarm system. Quarterly door seal inspections.', 'K. Govender', '2026-07-10', 'Active', 'R. Pillay'),
('RA-2026-0002', '2026-01-10', 'Waste Receiving', 'Manual Sorting', 'Sharps injuries', 'Workers may sustain needlestick injuries from improperly packaged sharps.', 3, 4, 12, 'High', 'Cut-resistant gloves. Sharps training. Rejection of non-compliant loads.', 'Double-glove protocol for pharmaceutical waste. Automated sorting feasibility study.', 'S. Naidoo', '2026-07-10', 'Active', 'R. Pillay'),
('RA-2026-0003', '2026-01-15', 'Chemical Storage', 'Chemical Handling', 'Chemical exposure', 'Skin or respiratory exposure to treatment chemicals during decanting or mixing.', 2, 3, 6, 'Medium', 'MSDS available. Chemical aprons and goggles required. Ventilation system.', 'Upgrade ventilation extraction. Install automated dosing system.', 'R. Pillay', '2026-07-15', 'Active', 'R. Pillay'),
('RA-2026-0004', '2026-02-05', 'Loading Bays', 'Vehicle Movements', 'Pedestrian-vehicle collision', 'Pedestrians at risk of being struck by reversing trucks or forklifts.', 3, 4, 12, 'High', 'Speed limits. Reversing alarms. Spotters for trucks.', 'Paint dedicated pedestrian walkways. Install barrier bollards.', 'J. Mokoena', '2026-08-05', 'Active', 'J. Mokoena'),
('RA-2026-0005', '2026-02-12', 'Workshop', 'Equipment Maintenance', 'Mechanical injury', 'Workers may suffer crush or entanglement injuries during maintenance tasks.', 2, 3, 6, 'Medium', 'LOTO procedures. Trained personnel only. Tool inspections.', 'Review LOTO signage. Annual refresher training.', 'K. Govender', '2026-08-12', 'Active', 'K. Govender'),
('RA-2026-0006', '2026-03-01', 'Full Site', 'Fire Emergency', 'Fire and smoke', 'Workers at risk of burns, smoke inhalation, or being trapped during a fire.', 1, 5, 5, 'Medium', 'Fire detection system. Extinguishers. Evacuation plan. Quarterly drills.', 'Extend sprinkler coverage to new storage area. Update evacuation maps.', 'R. Pillay', '2026-09-01', 'Active', 'R. Pillay'),
('RA-2026-0007', '2026-03-15', 'Effluent Treatment', 'Effluent Discharge', 'Water pollution', 'Non-compliant discharge could cause environmental damage and regulatory fines.', 2, 4, 8, 'High', 'Daily pH and turbidity testing. Automated dosing. Discharge permits.', 'Install continuous online monitoring with auto-shutoff valve.', 'R. Pillay', '2026-09-15', 'Active', 'R. Pillay'),
('RA-2026-0008', '2026-03-20', 'Full Site', 'Working at Heights', 'Falls from height', 'Workers accessing roof or elevated platforms may fall.', 2, 5, 10, 'High', 'Harness required above 2m. Guardrails on platforms. Permit to work system.', 'Annual harness inspection register. Height rescue plan.', 'J. Mokoena', '2026-09-20', 'Active', 'J. Mokoena'),
('RA-2026-0009', '2026-04-01', 'Treatment Plant', 'Noise Exposure', 'Hearing damage', 'Prolonged exposure to noise from autoclave and shredder operations.', 3, 3, 9, 'High', 'Hearing protection provided. Noise zones marked. Audiometric testing annual.', 'Engineering noise reduction study on shredder. Rotate high-noise tasks.', 'K. Govender', '2026-10-01', 'Active', 'K. Govender'),
('RA-2026-0010', '2026-04-10', 'Truck Operations', 'Driving', 'Road traffic accident', 'Drivers transporting waste on public roads may be involved in collisions.', 2, 4, 8, 'High', 'Licenced drivers only. Pre-trip checks. Speed monitoring via GPS.', 'Defensive driving refresher course. Fatigue management policy.', 'D. Mthembu', '2026-10-10', 'Active', 'D. Mthembu'),
('RA-2026-0011', '2026-05-01', 'Admin Building', 'Office Work', 'Ergonomic strain', 'Prolonged sitting and screen use can cause musculoskeletal problems.', 3, 2, 6, 'Medium', 'Adjustable chairs provided. Screen break reminders.', 'Ergonomic assessment for all workstations. Standing desk trial.', 'P. van Wyk', '2026-11-01', 'Draft', 'P. van Wyk'),
('RA-2026-0012', '2026-05-15', 'Chemical Storage', 'Chemical Incompatibility', 'Chemical reaction', 'Incompatible chemicals stored together could cause fire, explosion, or toxic gas.', 2, 5, 10, 'High', 'Segregated storage by class. MSDS available. Trained personnel.', 'Colour-coded shelving. Only trained staff to receive chemical deliveries.', 'R. Pillay', '2026-11-15', 'Active', 'R. Pillay');
