INSERT INTO safety_toolbox_talks (talk_number, talk_date, topic, description, presented_by, duration_minutes, attendee_count, attendees, location, follow_up_required, follow_up_notes) VALUES
('TBT-2026-0001', '2026-01-07', 'New Year Safety Restart', 'Review of safety procedures after holiday shutdown. Emphasis on re-familiarisation with equipment and PPE requirements.', 'J. Mokoena', 20, 28, 'All operational staff', 'Canteen', false, ''),
('TBT-2026-0002', '2026-01-14', 'Sharps Handling Safety', 'Safe handling of sharps containers, recognition of damaged packaging, and injury response protocol.', 'S. Naidoo', 25, 15, 'Treatment plant operators, receiving bay staff', 'Treatment Plant', true, 'Follow up with practical demonstration for new employees.'),
('TBT-2026-0003', '2026-01-28', 'Forklift & Pedestrian Safety', 'Rules for pedestrians in vehicle movement areas. Spotter requirements. Right of way rules.', 'D. Mthembu', 20, 22, 'Drivers, warehouse staff, loading bay workers', 'Loading Bay 1', false, ''),
('TBT-2026-0004', '2026-02-11', 'Lockout/Tagout Refresher', 'LOTO procedures for maintenance work. Review of recent near miss. Practical examples.', 'K. Govender', 30, 12, 'Maintenance team, plant operators', 'Workshop', false, ''),
('TBT-2026-0005', '2026-02-25', 'Chemical Safety & MSDS', 'How to read MSDS. Chemical storage requirements. Emergency procedures for spills.', 'R. Pillay', 25, 18, 'All plant staff', 'Canteen', false, ''),
('TBT-2026-0006', '2026-03-04', 'Slip, Trip & Fall Prevention', 'Identifying slip and trip hazards. Importance of housekeeping. Wet floor protocols.', 'P. van Wyk', 15, 25, 'All staff', 'Canteen', false, ''),
('TBT-2026-0007', '2026-03-18', 'Defensive Driving', 'Safe driving practices for waste collection routes. Fatigue management. Pre-trip checks.', 'D. Mthembu', 25, 10, 'All drivers', 'Training Room', true, 'Schedule formal defensive driving course for Q2.'),
('TBT-2026-0008', '2026-04-01', 'Fire Safety Awareness', 'Types of fire extinguishers and their uses. Evacuation routes. Assembly points.', 'R. Pillay', 20, 30, 'All staff', 'Canteen', false, ''),
('TBT-2026-0009', '2026-04-08', 'PPE Care & Maintenance', 'Proper use, storage, and inspection of PPE. When to request replacements.', 'S. Naidoo', 20, 18, 'All operational staff', 'Treatment Plant', false, ''),
('TBT-2026-0010', '2026-04-22', 'Incident Reporting Culture', 'Importance of reporting all incidents including near misses. No-blame reporting.', 'J. Mokoena', 20, 28, 'All staff', 'Canteen', false, ''),
('TBT-2026-0011', '2026-05-06', 'Environmental Awareness', 'Effluent management, storm water protection, waste segregation, and spill response.', 'R. Pillay', 25, 22, 'Plant operators, drivers, yard staff', 'Canteen', false, ''),
('TBT-2026-0012', '2026-05-13', 'Noise & Hearing Protection', 'Noise exposure limits. Correct use of ear protection. Audiometric testing schedule.', 'K. Govender', 20, 14, 'Treatment plant operators, maintenance', 'Treatment Plant', false, ''),
('TBT-2026-0013', '2026-05-20', 'Chemical Incompatibility', 'Recognising incompatible chemicals. Storage rules. What to do if mis-stored.', 'R. Pillay', 25, 16, 'All plant staff, receiving staff', 'Chemical Storage', true, 'Implement colour-coded shelf labels by end of month.'),
('TBT-2026-0014', '2026-05-27', 'Heat Stress Awareness', 'Recognising signs of heat exhaustion. Hydration requirements. Rest schedules in summer.', 'S. Naidoo', 15, 24, 'All outdoor and plant workers', 'Canteen', false, ''),
('TBT-2026-0015', '2026-03-25', 'Working at Heights', 'Fall protection requirements. Harness inspection. Permit to work process.', 'J. Mokoena', 25, 8, 'Maintenance team, contractors', 'Workshop', false, ''),
('TBT-2026-0016', '2026-04-15', 'Manual Handling', 'Correct lifting techniques. When to use mechanical aids. Back injury prevention.', 'P. van Wyk', 20, 20, 'All operational staff', 'Canteen', false, '');
INSERT INTO safety_emergency_drills (drill_number, drill_date, drill_type, location, coordinator, participants_count, evacuation_time_seconds, target_time_seconds, passed, observations, improvements, next_drill_date, status) VALUES
('DRL-2026-0001', '2026-01-15', 'Fire Evacuation', 'Full Site', 'R. Pillay', 32, 195, 180, false, 'Treatment plant staff took longer due to LOTO requirements before evacuation. Assembly point B had delayed roll call.', 'Pre-assign LOTO buddies for faster shutdown. Appoint additional assembly point marshals.', '2026-04-15', 'Completed'),
('DRL-2026-0002', '2026-02-12', 'Chemical Spill', 'Chemical Storage', 'R. Pillay', 8, 0, 0, true, 'Spill response team deployed containment within 4 minutes. Correct PPE donned. MSDS referenced appropriately.', 'Label spill kits more prominently. Add emergency contact card to each kit.', '2026-05-12', 'Completed'),
('DRL-2026-0003', '2026-03-05', 'Medical Emergency', 'Treatment Plant', 'S. Naidoo', 6, 0, 0, true, 'First aiders responded promptly. Correct use of emergency eyewash. Ambulance contact simulated successfully.', 'Update first aid kit inventory in treatment area. Add second eyewash station.', '2026-06-05', 'Completed'),
('DRL-2026-0004', '2026-04-15', 'Fire Evacuation', 'Full Site', 'R. Pillay', 35, 168, 180, true, 'Significant improvement. LOTO buddy system worked well. All personnel accounted for within target time.', 'Continue quarterly drills. Test night shift evacuation next.', '2026-07-15', 'Completed'),
('DRL-2026-0005', '2026-05-12', 'Chemical Spill', 'Treatment Plant', 'R. Pillay', 10, 0, 0, true, 'Spill in treatment area simulated. Team contained spill in 3 minutes. Ventilation activated correctly.', 'Practice with larger simulated spill next time. Include waste neutralisation step.', '2026-08-12', 'Completed'),
('DRL-2026-0006', '2026-05-20', 'Medical Emergency', 'Loading Bay', 'S. Naidoo', 5, 0, 0, true, 'Simulated crush injury. First aiders applied splint correctly. Communication to emergency services clear.', 'Add trauma first aid refresher to next training cycle.', '2026-08-20', 'Completed'),
('DRL-2026-0007', '2026-06-15', 'Fire Evacuation', 'Full Site', 'R. Pillay', 0, 0, 180, false, '', '', '2026-09-15', 'Scheduled'),
('DRL-2026-0008', '2026-07-10', 'Chemical Spill', 'Chemical Storage', 'R. Pillay', 0, 0, 0, false, '', '', '2026-10-10', 'Scheduled');
